import{_ as s,o as i,c as n,ae as e}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"Nix","description":"Nix를 사용하여 선언적으로 OpenClaw 설치","frontmatter":{"title":"Nix","description":"Nix를 사용하여 선언적으로 OpenClaw 설치"},"headers":[],"relativePath":"install/nix.md","filePath":"install/nix.md","lastUpdated":null}'),l={name:"install/nix.md"};function t(p,a,h,r,o,d){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="nix-설치" tabindex="-1">Nix 설치 <a class="header-anchor" href="#nix-설치" aria-label="Permalink to &quot;Nix 설치&quot;">​</a></h1><p>**<a href="https://github.com/openclaw/nix-openclaw" target="_blank" rel="noreferrer">nix-openclaw</a>**를 사용하여 선언적으로 OpenClaw를 설치합니다 -- 배터리가 포함된 Home Manager 모듈.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><a href="https://github.com/openclaw/nix-openclaw" target="_blank" rel="noreferrer">nix-openclaw</a> 저장소는 Nix 설치의 단일 진실 공급원입니다. 이 페이지는 간략한 개요입니다.</p></div><h2 id="제공-내용" tabindex="-1">제공 내용 <a class="header-anchor" href="#제공-내용" aria-label="Permalink to &quot;제공 내용&quot;">​</a></h2><ul><li>Gateway + macOS 앱 + 도구 (whisper, spotify, cameras) -- 모두 고정됨</li><li>재부팅 후에도 유지되는 Launchd 서비스</li><li>선언적 구성이 포함된 플러그인 시스템</li><li>즉각적인 롤백: <code>home-manager switch --rollback</code></li></ul><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><ol><li><p><strong>Determinate Nix 설치</strong></p><p>Nix가 아직 설치되지 않은 경우 <a href="https://github.com/DeterminateSystems/nix-installer" target="_blank" rel="noreferrer">Determinate Nix 설치 프로그램</a> 지침을 따릅니다.</p></li><li><p><strong>로컬 플레이크 생성</strong></p></li></ol><p>nix-openclaw 저장소의 에이전트 우선 템플릿을 사용합니다: <code>bash mkdir -p ~/code/openclaw-local # nix-openclaw 저장소에서 templates/agent-first/flake.nix 복사 </code></p><ol start="3"><li><strong>시크릿 구성</strong></li></ol><p>메시징 봇 토큰 및 모델 제공자 API 키를 설정합니다. <code>~/.secrets/</code>의 일반 파일로 충분합니다.</p><ol start="4"><li><strong>템플릿 플레이스홀더 채우기 및 전환</strong></li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    home-manager</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> switch</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    \`\`\`</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">5.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> **</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">확인</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">**</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 서비스가 실행 중이고 봇이 메시지에 응답하는지 확인합니다.</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">전체</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 모듈 옵션 및 예제는 [nix-openclaw README](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://github.com/openclaw/nix-openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)를 참조하십시오.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## Nix 모드 런타임 동작</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_NIX_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1\`</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">이</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 설정되면(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nix-openclaw로</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 자동 설정) OpenClaw는 자동 설치 흐름을 비활성화하는 결정론적 모드에 진입합니다.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">수동으로</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 설정할 수도 있습니다:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`\`\`</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENCLAW_NIX_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><p>macOS에서 GUI 앱은 셸 환경 변수를 자동으로 상속하지 않습니다. 대신 defaults를 통해 Nix 모드를 활성화합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">defaults</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.openclaw.mac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw.nixMode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -bool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre></div><h3 id="nix-모드에서-변경되는-사항" tabindex="-1">Nix 모드에서 변경되는 사항 <a class="header-anchor" href="#nix-모드에서-변경되는-사항" aria-label="Permalink to &quot;Nix 모드에서 변경되는 사항&quot;">​</a></h3><ul><li>자동 설치 및 자기 변경 흐름이 비활성화됩니다</li><li>누락된 종속성이 Nix 전용 수정 메시지를 표시합니다</li><li>UI가 읽기 전용 Nix 모드 배너를 표시합니다</li></ul><h3 id="구성-및-상태-경로" tabindex="-1">구성 및 상태 경로 <a class="header-anchor" href="#구성-및-상태-경로" aria-label="Permalink to &quot;구성 및 상태 경로&quot;">​</a></h3><p>OpenClaw는 <code>OPENCLAW_CONFIG_PATH</code>에서 JSON5 구성을 읽고 변경 가능한 데이터를 <code>OPENCLAW_STATE_DIR</code>에 저장합니다. Nix에서 실행할 때 런타임 상태와 구성이 불변 저장소를 벗어나도록 Nix 관리 위치로 이것들을 명시적으로 설정합니다.</p><table tabindex="0"><thead><tr><th>변수</th><th>기본값</th></tr></thead><tbody><tr><td><code>OPENCLAW_HOME</code></td><td><code>HOME</code> / <code>USERPROFILE</code> / <code>os.homedir()</code></td></tr><tr><td><code>OPENCLAW_STATE_DIR</code></td><td><code>~/.openclaw</code></td></tr><tr><td><code>OPENCLAW_CONFIG_PATH</code></td><td><code>$OPENCLAW_STATE_DIR/openclaw.json</code></td></tr></tbody></table><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="https://github.com/openclaw/nix-openclaw" target="_blank" rel="noreferrer">nix-openclaw</a> -- 전체 설정 가이드</li><li><a href="/openclaw-docs-ko/start/wizard">마법사</a> -- Nix를 사용하지 않는 CLI 설정</li><li><a href="/openclaw-docs-ko/install/docker">Docker</a> -- 컨테이너화된 설정</li></ul>`,21)])])}const F=s(l,[["render",t]]);export{k as __pageData,F as default};
